  1→/**
  2→ * Session Query Hooks
  3→ * TanStack Query hooks for Claude Code session management
  4→ */
  5→
  6→import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
  7→import { produce } from "immer";
  8→import { SessionService } from "./session.service";
  9→import type { PaginatedMessages } from "./session.service";
 10→import { queryKeys } from "@/shared/api/queryKeys";
 11→import {
 12→  MESSAGE_PAGE_SIZE,
 13→  INITIAL_MESSAGE_PAGE_SIZE,
 14→  incrementalFetchAndMerge,
 15→} from "../lib/messageCache";
 16→import type { ContentBlock, Message, Session, SessionStatus, ToolResultBlock } from "../types";
 17→import { isToolResultBlock } from "../types";
 18→import type { RepoGroup } from "@shared/types/workspace";
 19→import { useMemo, useCallback } from "react";
 20→import { track } from "@/platform/analytics";
 21→import { parseContentBlocks } from "../lib/contentParser";
 22→import { socketService } from "@/platform/socket";
 23→import type { RuntimeAgentType } from "../lib/agentRuntime";
 24→
 25→/**
 26→ * Fetch all sessions for a workspace (used by chat tab reconstruction).
 27→ * Stale time is high — tabs only hydrate on mount and after creating new sessions.
 28→ */
 29→export function useWorkspaceSessions(workspaceId: string | null) {
 30→  return useQuery({
 31→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 32→    queryFn: () => SessionService.fetchByWorkspace(workspaceId!),
 33→    enabled: !!workspaceId,
 34→    staleTime: 30_000,
 35→  });
 36→}
 37→
 38→/**
 39→ * Fetch session details — fully event-driven, no polling.
 40→ *
 41→ * Updates come from Tauri events handled by useSessionEvents:
 42→ * - session:status-changed → setQueryData (direct cache write)
 43→ * - session:error → setQueryData (direct cache write)
 44→ *
 45→ * On mount, useSessionEvents does a catch-up fetch + invalidateQueries
 46→ * to reconcile any changes missed while unmounted (navigation, app reopen).
 47→ */
 48→export function useSession(sessionId: string | null) {
 49→  return useQuery({
 50→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 51→    queryFn: () => SessionService.fetchById(sessionId!),
 52→    enabled: !!sessionId,
 53→    staleTime: 10_000,
 54→  });
 55→}
 56→
 57→/**
 58→ * Subscribe to per-session working status for multiple sessions at once.
 59→ * Used by the tab bar to show per-tab spinners correctly.
 60→ *
 61→ * The workspace's single `session_status` field breaks with multiple tabs —
 62→ * it gets overwritten by whichever session's event fires last. This hook
 63→ * subscribes to each session's detail cache reactively so tab spinners
 64→ * reflect each session's actual status.
 65→ *
 66→ * No extra HTTP fetches when data is already in cache (populated by
 67→ * useSessionEvents via setQueryData on status changes).
 68→ */
 69→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 70→  const queries = useQueries({
 71→    queries: sessionIds.map((id) => ({
 72→      queryKey: queryKeys.sessions.detail(id),
 73→      queryFn: () => SessionService.fetchById(id),
 74→      staleTime: 30_000,
 75→      select: (data: Session): SessionStatus => data.status,
 76→    })),
 77→  });
 78→
 79→  // Derive a stable string key from statuses to avoid creating a new Set
 80→  // on every render — only re-compute when a status actually changes.
 81→  const statusKey = queries.map((q) => q.data ?? "unknown").join(",");
 82→
 83→  // eslint-disable-next-line react-hooks/exhaustive-deps
 84→  return useMemo(() => {
 85→    const ids = new Set<string>();
 86→    sessionIds.forEach((id, i) => {
 87→      if (queries[i]?.data === "working") ids.add(id);
 88→    });
 89→    return ids;
 90→  }, [statusKey, sessionIds]);
 91→}
 92→
 93→/**
 94→ * Fetch messages for a session with smart fallback
 95→ * - Desktop (Tauri): Real-time events, no polling
 96→ * - Web (Browser): Smart polling when session is working
 97→ *
 98→ * Returns Message[] via `select` so downstream consumers are unchanged.
 99→ * Raw cache holds PaginatedMessages for optimistic updates.
100→ */
101→export function useMessages(sessionId: string | null) {
102→  const query = useQuery({
103→    queryKey: queryKeys.sessions.messages(sessionId || ""),
104→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
105→    enabled: !!sessionId,
106→    // No select — expose full PaginatedMessages for has_older/has_newer.
107→    // All updates are manual: Tauri events do incremental fetch, web mode uses polling hook.
108→    refetchInterval: false,
109→    staleTime: Infinity,
110→  });
111→
112→  return query;
113→}
114→
115→/**
116→ * Combined hook for session + messages + status
117→ * Replaces the complex useMessages hook
118→ */
119→export function useSessionWithMessages(sessionId: string | null) {
120→  const sessionQuery = useSession(sessionId);
121→  const messagesQuery = useMessages(sessionId);
122→
123→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
124→  const messages = messagesQuery.data?.messages ?? [];
125→  const hasOlder = messagesQuery.data?.has_older ?? false;
126→
127→  // Parse content helper — delegates to pure function in lib/contentParser.ts
128→  // Memoized to prevent Context cascade re-renders
129→  const parseContent = useCallback(
130→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
131→    []
132→  );
133→
134→  // Build tool result map and parent_tool_use_id map in a single pass.
135→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
136→    const resultMap = new Map();
137→    const parentMap = new Map<string, string>();
138→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
139→
140→    messages.forEach((msg: Message) => {
141→      if (msg.parent_tool_use_id) {
142→        parentMap.set(msg.id, msg.parent_tool_use_id);
143→      }
144→
145→      const blocks = parseContent(msg.content);
146→      if (Array.isArray(blocks)) {
147→        blocks.filter(isToolResultBlock).forEach((block) => {
148→          resultMap.set(block.tool_use_id, block);
149→        });
150→      }
151→    });
152→
153→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
154→  }, [messages, parseContent]);
155→
156→  // Group subagent messages by their parent Task tool_use_id
157→  const subagentMessages = useMemo(() => {
158→    const map = new Map<string, Message[]>();
159→    if (!messages.length) return map;
160→
161→    messages.forEach((msg: Message) => {
162→      const parentId = parentToolUseMap.get(msg.id);
163→      if (parentId) {
164→        if (!map.has(parentId)) map.set(parentId, []);
165→        map.get(parentId)!.push(msg);
166→      }
167→    });
168→
169→    return map;
170→  }, [messages, parentToolUseMap]);
171→
172→  // Get latest user message's sent_at for duration tracking
173→  const latestMessageSentAt = useMemo(() => {
174→    if (!messages.length) return null;
175→
176→    // Find the latest user message
177→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
178→
179→    return latestUserMessage?.sent_at || null;
180→  }, [messages]);
181→
182→  return {
183→    session: sessionQuery.data,
184→    messages,
185→    hasOlder,
186→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
187→    latestMessageSentAt,
188→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
189→    error: sessionQuery.error || messagesQuery.error,
190→    parseContent,
191→    toolResultMap,
192→    parentToolUseMap,
193→    subagentMessages,
194→  };
195→}
196→
197→/**
198→ * Load older messages (scroll-up pagination).
199→ * Prepends older messages to the cache while preserving has_newer from current cache.
200→ */
201→export function useLoadOlderMessages() {
202→  const queryClient = useQueryClient();
203→
204→  return useMutation({
205→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
206→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
207→
208→    onSuccess: (olderPage, { sessionId }) => {
209→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
210→        if (!old) return olderPage;
211→        // Deduplicate by id (shouldn't happen, but safety first)
212→        const existingIds = new Set(old.messages.map((m) => m.id));
213→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
214→        return {
215→          messages: [...newMessages, ...old.messages],
216→          has_older: olderPage.has_older,
217→          has_newer: old.has_newer,
218→        };
219→      });
220→    },
221→  });
222→}
223→
224→/**
225→ * Send message mutation with optimistic update
226→ *
227→ * Shows user message immediately in the chat while request is in flight.
228→ * The optimistic message has a temporary ID that gets replaced on refetch.
229→ */
230→export function useSendMessage() {
231→  const queryClient = useQueryClient();
232→
233→  return useMutation({
234→    mutationFn: async ({
235→      sessionId,
236→      content,
237→      model,
238→      cwd,
239→      agentType,
240→    }: {
241→      sessionId: string;
242→      content: string;
243→      model?: string;
244→      cwd?: string;
245→      agentType?: RuntimeAgentType;
246→    }): Promise<Message | void> => {
247→      // Desktop (Tauri): sidecar saves message + starts agent atomically.
248→      // The sidecar's onQuery handler persists the user message and sets
249→      // status='working' in a single SQLite transaction before dispatching
250→      // the agent — no partial-commit failure mode.
251→      if (cwd) {
252→        const ack = await socketService.sendQuery(
253→          sessionId,
254→          content,
255→          { cwd, model },
256→          agentType || "claude"
257→        );
258→        if (!ack.accepted) {
259→          throw new Error(ack.reason || "Agent rejected the query");
260→        }
261→        // No return value needed — onSettled ignores the mutationFn result.
262→        // The real message is in the DB; incremental fetch in onSettled picks it up.
263→        return;
264→      }
265→      // Gateway/web fallback: HTTP POST to backend
266→      return SessionService.sendMessage(sessionId, content, model);
267→    },
268→
269→    // Optimistic update: show user message immediately.
270→    // Status indicators (tab spinner, sidebar) are event-driven — the sidecar
271→    // emits session:status-changed which arrives within ~50ms via Tauri events.
272→    // Both useSessionEvents and useGlobalSessionNotifications write directly
273→    // to their respective caches via setQueryData (no HTTP round-trip).
274→    onMutate: async ({ sessionId, content, model }) => {
275→      await queryClient.cancelQueries({
276→        queryKey: queryKeys.sessions.messages(sessionId),
277→      });
278→
279→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
280→        queryKeys.sessions.messages(sessionId)
281→      );
282→
283→      // Snapshot workspace-by-repo cache before optimistic update so we can
284→      // restore the exact prior status on error (instead of hardcoding "idle").
285→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
286→        queryKey: ["workspaces", "by-repo"],
287→      });
288→
289→      // Create optimistic user message
290→      const optimisticId =
291→        typeof crypto !== "undefined" && "randomUUID" in crypto
292→          ? `optimistic-${crypto.randomUUID()}`
293→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
294→
295→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
296→      let optimisticContentJson: string;
297→      try {
298→        const parsed = JSON.parse(content);
299→        if (Array.isArray(parsed)) {
300→          optimisticContentJson = JSON.stringify(parsed);
301→        } else {
302→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
303→        }
304→      } catch {
305→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
306→      }
307→
308→      const optimisticMessage: Message = {
309→        id: optimisticId,
310→        session_id: sessionId,
311→        seq: Number.MAX_SAFE_INTEGER,
312→        role: "user",
313→        content: optimisticContentJson,
314→        sent_at: new Date().toISOString(),
315→        model: model ?? null,
316→      };
317→
318→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
319→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
320→        return produce(old, (draft) => {
321→          draft.messages.push(optimisticMessage);
322→        });
323→      });
324→
325→      // Optimistically set workspace status to "working" in sidebar cache.
326→      // Handles the startup race where the first Tauri event arrives before
327→      // the workspace list has loaded (cache empty → event matching fails).
328→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
329→        if (!old) return old;
330→        return old.map((group) => ({
331→          ...group,
332→          workspaces: group.workspaces.map((ws) =>
333→            ws.current_session_id === sessionId
334→              ? { ...ws, session_status: "working" as SessionStatus }
335→              : ws
336→          ),
337→        }));
338→      });
339→
340→      return { previousMessages, previousWorkspaceByRepo };
341→    },
342→
343→    onError: (_err, variables, context) => {
344→      // Roll back optimistic message
345→      if (context?.previousMessages) {
346→        queryClient.setQueryData(
347→          queryKeys.sessions.messages(variables.sessionId),
348→          context.previousMessages
349→        );
350→      } else {
351→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
352→        queryClient.invalidateQueries({
353→          queryKey: queryKeys.sessions.messages(variables.sessionId),
354→        });
355→      }
356→      // Roll back optimistic workspace status from snapshot
357→      if (context?.previousWorkspaceByRepo?.length) {
358→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
359→          queryClient.setQueryData(key, data);
360→        });
361→      } else {
362→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
363→      }
364→    },
365→
366→    onSettled: async (_, error, variables) => {
367→      if (!error) {
368→        const hasImages = (() => {
369→          try {
370→            const parsed = JSON.parse(variables.content);
371→            return (
372→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
373→            );
374→          } catch {
375→            return false;
376→          }
377→        })();
378→        const session = queryClient.getQueryData<Session>(
379→          queryKeys.sessions.detail(variables.sessionId)
380→        );
381→        track("session_message_sent", {
382→          session_id: variables.sessionId,
383→          has_images: hasImages,
384→          model: variables.model,
385→          agent_type: session?.agent_type,
386→          message_count: session?.message_count,
387→          context_used_percent: session?.context_used_percent,
388→        });
389→      }
390→
391→      // Reconcile optimistic placeholder with real DB record.
392→      // Session detail is NOT invalidated here — status updates arrive via
393→      // session:status-changed Tauri events handled by useSessionEvents.
394→      await incrementalFetchAndMerge(
395→        queryClient,
396→        variables.sessionId,
397→        queryKeys.sessions.messages(variables.sessionId)
398→      );
399→    },
400→  });
401→}
402→
403→/**
404→ * Stop session mutation
405→ */
406→export function useStopSession() {
407→  const queryClient = useQueryClient();
408→
409→  return useMutation({
410→    mutationFn: (sessionId: string) => SessionService.stop(sessionId),
411→    onSuccess: (_, sessionId) => {
412→      const session = queryClient.getQueryData<Session>(queryKeys.sessions.detail(sessionId));
413→      track("session_stopped", {
414→        session_id: sessionId,
415→        agent_type: session?.agent_type,
416→      });
417→      // Immediate invalidation for snappy UI feedback (~50ms faster than event path).
418→      // Backend also calls invalidate(["workspaces","sessions","stats"]) which flows
419→      // through Tauri events → useQueryInvalidation. React Query deduplicates.
420→      queryClient.invalidateQueries({
421→        queryKey: queryKeys.sessions.detail(sessionId),
422→      });
423→      queryClient.invalidateQueries({
424→        queryKey: queryKeys.workspaces.all,
425→      });
426→    },
427→  });
428→}
429→
430→/**
431→ * Create a new session for a workspace.
432→ * Used when user opens a new chat tab (Cmd+T).
433→ * Backend creates the session and updates workspace.current_session_id.
434→ */
435→export function useCreateSession() {
436→  const queryClient = useQueryClient();
437→
438→  return useMutation({
