  1→/**
  2→ * Session Events Hook
  3→ *
  4→ * Listens for real-time session events from Tauri and updates React Query cache
  5→ * Only works in Tauri mode (desktop app)
  6→ *
  7→ * ARCHITECTURE (Event Flow) - Updated for sidecar-v2:
  8→ * 1. Sidecar-v2 receives Claude SDK response
  9→ * 2. Sidecar-v2 saves message to SQLite (directly)
 10→ * 3. Sidecar-v2 sends JSON-RPC notification to Rust socket
 11→ * 4. Rust parses notification → emits Tauri event
 12→ * 5. This hook receives event → invalidates React Query cache
 13→ * 6. UI updates instantly (<100ms latency)
 14→ *
 15→ * MEMORY LEAK FIX (2025-10-26):
 16→ * - Was: Stored unlisten function in variable, race condition if unmount before promise resolves
 17→ * - Now: Store promise itself, cleanup awaits promise (guaranteed cleanup)
 18→ * - Prevents orphaned listeners on fast navigation between sessions
 19→ */
 20→
 21→import { useEffect } from "react";
 22→import { useQueryClient } from "@tanstack/react-query";
 23→import { queryKeys } from "@/shared/api/queryKeys";
 24→import {
 25→  isTauriEnv,
 26→  listen,
 27→  createListenerGroup,
 28→  SESSION_MESSAGE,
 29→  SESSION_ERROR,
 30→  SESSION_STATUS_CHANGED,
 31→} from "@/platform/tauri";
 32→import { incrementalFetchAndMerge } from "../lib/messageCache";
 33→import type { Session } from "../types";
 34→
 35→/**
 36→ * Listen for real-time session message events
 37→ *
 38→ * When Claude responds:
 39→ * 1. Sidecar-v2 receives Claude SDK response
 40→ * 2. Sidecar-v2 saves to SQLite & sends JSON-RPC notification
 41→ * 3. Rust emits Tauri event "session:message"
 42→ * 4. This hook receives event
 43→ * 5. Invalidates React Query cache
 44→ * 6. UI updates instantly
 45→ */
 46→export function useSessionEvents(sessionId: string | null, workspaceId?: string | null) {
 47→  const queryClient = useQueryClient();
 48→
 49→  useEffect(() => {
 50→    // Only work in Tauri mode (desktop app)
 51→    if (!isTauriEnv || !sessionId) {
 52→      return;
 53→    }
 54→
 55→    // Catch-up fetch: reconcile any messages missed while this hook was unmounted
 56→    // (navigation to another session, socket hiccup, app backgrounded, etc.).
 57→    // One cheap DB query on mount — handles ALL stale-cache scenarios.
 58→    incrementalFetchAndMerge(queryClient, sessionId, queryKeys.sessions.messages(sessionId));
 59→    // Also refresh session detail to catch status changes (working→idle during navigation)
 60→    queryClient.invalidateQueries({
 61→      queryKey: queryKeys.sessions.detail(sessionId),
 62→    });
 63→
 64→    const listeners = createListenerGroup();
 65→
 66→    // Listen for message events from sidecar-v2
 67→    listeners.register(
 68→      listen(SESSION_MESSAGE, (event) => {
 69→        const { id, data } = event.payload;
 70→
 71→        // Only process events for this session
 72→        if (id === sessionId) {
 73→          if (import.meta.env.DEV) {
 74→            const dataType = (data as Record<string, unknown>)?.type;
 75→            console.log("[Events] Message received:", { dataType });
 76→          }
 77→
 78→          // Incremental fetch: only get messages newer than what we have.
 79→          // Session detail is NOT invalidated here — status changes arrive via
 80→          // the dedicated session:status-changed event listener below.
