  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Listens to ALL session events (not just the selected one) and sends
  5→ * OS-level notifications when the app is in the background.
  6→ *
  7→ * Notification triggers:
  8→ * - Agent finished working (working → idle)         → Glass sound
  9→ * - Agent error (session:error event)                → Basso sound
 10→ * - Agent needs input (→ needs_response)             → Ping sound
 11→ * - Plan ready for review (session:enter-plan-mode)  → Ping sound
 12→ *
 13→ * When the app is in the foreground, notifications are suppressed —
 14→ * Sonner toasts handle in-app feedback.
 15→ */
 16→
 17→import { useEffect, useRef } from "react";
 18→import { useQueryClient } from "@tanstack/react-query";
 19→import { match } from "ts-pattern";
 20→import {
 21→  isTauriEnv,
 22→  listen,
 23→  createListenerGroup,
 24→  SESSION_ERROR,
 25→  SESSION_ENTER_PLAN_MODE,
 26→  SESSION_STATUS_CHANGED,
 27→} from "@/platform/tauri";
 28→import { sendNotification } from "@/platform/notifications";
 29→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 30→import { track } from "@/platform/analytics";
 31→import { applySessionStatusToRepoGroups } from "@/features/workspace/lib/dashboardRealtime";
 32→import type { SessionStatus } from "@shared/types/session";
 33→import type { RepoGroup, SetupStatus } from "@shared/types/workspace";
 34→
 35→/**
 36→ * Batches multiple notifications within a short window into a single one.
 37→ * Prevents notification spam when multiple agents finish simultaneously.
 38→ */
 39→const BATCH_WINDOW_MS = 1500;
 40→
 41→export function useGlobalSessionNotifications() {
 42→  // Track previous session statuses for transition detection
 43→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 44→  // Track previous workspace setup statuses for setup failure notifications
 45→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 46→  // Batch queue for "agent finished" notifications
 47→  const finishedBatch = useRef<string[]>([]);
 48→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 49→
 50→  const queryClient = useQueryClient();
 51→
 52→  useEffect(() => {
 53→    if (!isTauriEnv) return;
 54→
 55→    const listeners = createListenerGroup();
 56→
 57→    function flushFinishedBatch() {
 58→      const batch = finishedBatch.current;
 59→      finishedBatch.current = [];
 60→      batchTimerRef.current = undefined;
 61→
 62→      if (batch.length === 0 || isWindowFocused()) return;
 63→
 64→      if (batch.length === 1) {
 65→        sendNotification({
 66→          title: "Agent finished",
 67→          body: `Session ${batch[0].substring(0, 8)} completed`,
 68→          sound: "Glass",
 69→        });
 70→      } else {
 71→        sendNotification({
 72→          title: `${batch.length} agents finished`,
 73→          body: "Multiple sessions completed",
 74→          sound: "Glass",
 75→        });
 76→      }
 77→    }
 78→
 79→    function queueFinished(sessionId: string) {
 80→      finishedBatch.current.push(sessionId);
 81→      if (!batchTimerRef.current) {
 82→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
 83→      }
 84→    }
 85→
 86→    // --- Error notifications (instant, category-aware) ---
 87→    listeners.register(
 88→      listen(SESSION_ERROR, (event) => {
 89→        const { id, error, category } = event.payload;
 90→
 91→        // Analytics fires regardless of window focus — we always want error data
 92→        track("session_error_displayed", {
 93→          session_id: id,
 94→          error_category: category,
 95→        });
 96→
 97→        if (isWindowFocused()) return;
 98→
 99→        const title = match(category)
100→          .with("auth", () => "Authentication Error")
101→          .with("rate_limit", () => "Rate Limited")
102→          .with("context_limit", () => "Context Limit Reached")
103→          .with("network", () => "Network Error")
104→          .with("db_write", () => "Database Error")
105→          .with("process_exit", () => "Agent Process Crashed")
106→          .otherwise(() => "Agent Error");
107→        sendNotification({
108→          title,
109→          body: error || `Session ${id.substring(0, 8)} encountered an error`,
110→          sound: "Basso",
111→        });
112→      })
113→    );
114→
115→    // --- Plan mode notifications (instant) ---
116→    listeners.register(
117→      listen(SESSION_ENTER_PLAN_MODE, (event) => {
118→        if (isWindowFocused()) return;
119→
120→        const { id } = event.payload;
121→        sendNotification({
122→          title: "Plan ready for review",
123→          body: `Session ${id.substring(0, 8)} has a plan waiting for approval`,
124→          sound: "Ping",
125→        });
126→      })
127→    );
128→
129→    // --- Global status change → sidebar cache + transition notifications ---
130→    // useSessionEvents only handles the *current* session. This global listener
131→    // ensures sidebar status indicators update for ALL sessions instantly.
132→    //
133→    // Notification policy hangs off this authoritative domain event rather than
134→    // React Query cache transitions (a derived view). This avoids timing issues
135→    // if cache updates are batched, deferred, or arrive out of order.
136→    listeners.register(
137→      listen(SESSION_STATUS_CHANGED, (event) => {
138→        const { id, status } = event.payload;
139→
140→        // 1. Patch sidebar cache directly (no HTTP round-trip)
141→        queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) =>
142→          applySessionStatusToRepoGroups(old, event.payload)
143→        );
144→
145→        // 2. Detect status transitions for analytics + notifications
146→        const prevStatus = prevStatusMap.current.get(id);
147→        prevStatusMap.current.set(id, status as SessionStatus);
148→
149→        if (!prevStatus || prevStatus === status) return;
150→
151→        // working → idle = agent finished — track regardless of window focus
152→        if (prevStatus === "working" && status === "idle") {
153→          track("ai_turn_completed", {
154→            session_id: id,
155→            agent_type: event.payload.agentType,
156→          });
157→        }
158→
159→        if (isWindowFocused()) return;
160→
161→        // working → idle = agent finished (notification only when backgrounded)
162→        if (prevStatus === "working" && status === "idle") {
163→          queueFinished(id);
164→        }
165→
166→        // → needs_response = agent needs user input
167→        if (status === "needs_response") {
168→          sendNotification({
169→            title: "Agent needs input",
170→            body: `Session ${id.substring(0, 8)} is waiting for your response`,
171→            sound: "Ping",
172→          });
173→        }
174→
175→        // Error and plan-mode notifications are handled by the direct Tauri
176→        // event listeners above (session:error, session:enter-plan-mode) which
177→        // fire immediately — no need to duplicate them here.
178→      })
179→    );
180→
181→    // --- Setup failure notifications via workspace cache ---
182→    const unsubscribeWorkspaces = queryClient.getQueryCache().subscribe((event) => {
183→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
184→
185→      // Watch workspace list queries: ["workspaces", "by-repo", ...]
186→      const key = event.query.queryKey;
187→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
188→
189→      const groups = event.query.state.data as RepoGroup[] | undefined;
190→      if (!groups) return;
191→
192→      for (const group of groups) {
193→        for (const ws of group.workspaces) {
194→          const prev = prevSetupStatusMap.current.get(ws.id);
195→          prevSetupStatusMap.current.set(ws.id, ws.setup_status);
196→
197→          if (!prev) continue; // First observation
198→          if (prev === ws.setup_status) continue; // No transition
199→
200→          // running → failed/completed = setup finished — track analytics always
201→          if (
202→            prev === "running" &&
203→            (ws.setup_status === "failed" || ws.setup_status === "completed")
204→          ) {
205→            track("workspace_setup_completed", {
206→              workspace_id: ws.id,
207→              setup_status: ws.setup_status,
208→            });
209→          }
210→
211→          // running → failed = setup failed
212→          if (prev === "running" && ws.setup_status === "failed" && !isWindowFocused()) {
213→            sendNotification({
214→              title: "Setup failed",
215→              body: `Workspace ${ws.title || ws.slug} setup failed${ws.error_message ? `: ${ws.error_message}` : ""}`,
216→              sound: "Basso",
217→            });
218→          }
219→
220→          // running → completed = setup finished (success)
221→          if (prev === "running" && ws.setup_status === "completed") {
222→            // Invalidate manifest cache so task buttons appear
223→            queryClient.invalidateQueries({ queryKey: ["workspaces", "manifest", ws.id] });
224→
225→            if (!isWindowFocused()) {
226→              sendNotification({
227→                title: "Setup complete",
228→                body: `Workspace ${ws.title || ws.slug} is ready`,
229→                sound: "Glass",
230→              });
231→            }
232→          }
233→        }
234→      }
235→    });
236→
237→    return () => {
238→      listeners.cleanup();
239→      unsubscribeWorkspaces();
240→      if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
241→    };
242→  }, [queryClient]);
243→}
