  1→// src/features/session/hooks/useAgentRpcHandler.ts
  2→//
  3→// Handles agent-initiated RPC requests that require frontend interaction or data access.
  4→//
  5→// Architecture:
  6→//   Sidecar → Rust socket relay → "sidecar:request" Tauri event → this handler
  7→//   Handler responds via: invoke("send_sidecar_message", { message: JSON.stringify(...) })
  8→//
  9→// Multiple listeners on "sidecar:request" are fine — browser automation uses the same event.
 10→// This hook only claims the 5 agent-UI methods; everything else falls through.
 11→//
 12→// Handled methods:
 13→//   exitPlanMode         — user must approve/reject an agent plan (UI interaction needed)
 14→//   askUserQuestion      — agent asks structured questions with options (UI interaction needed)
 15→//   getDiff              — agent reads workspace diff (data fetch, auto-responds)
 16→//   diffComment          — agent posts comments on diff (stored, auto-responds success)
 17→//   getTerminalOutput    — agent reads terminal output (auto-responds from Tauri PTY)
 18→//
 19→// Pending state is stored in a Map<sessionId, PendingRequest> so multiple concurrent
 20→// agent sessions can each have their own pending request simultaneously.
 21→
 22→import { match } from "ts-pattern";
 23→import { useEffect, useLayoutEffect, useCallback, useRef, useState } from "react";
 24→import { invoke, listen, isTauriEnv, SIDECAR_REQUEST } from "@/platform/tauri";
 25→import { getErrorMessage } from "@shared/lib/errors";
 26→import { gitDiffFiles, gitDiffFile } from "@/platform/tauri/git";
 27→
 28→// ============================================================================
 29→// Types
 30→// ============================================================================
 31→
 32→export interface PlanModeRequest {
 33→  type: "exitPlanMode";
 34→  rpcId: unknown;
 35→  sessionId: string;
 36→  toolInput: unknown;
 37→}
 38→
 39→export interface AskQuestionRequest {
 40→  type: "askUserQuestion";
 41→  rpcId: unknown;
 42→  sessionId: string;
 43→  questions: Array<{
 44→    question: string;
 45→    options: string[];
 46→    multiSelect?: boolean;
 47→  }>;
 48→}
 49→
 50→export type PendingAgentRequest = PlanModeRequest | AskQuestionRequest;
 51→
 52→// ============================================================================
 53→// Hook
 54→// ============================================================================
 55→
 56→/**
 57→ * Context needed to auto-respond to data-fetch requests (getDiff, getTerminalOutput).
 58→ * The workspace providing this must match the session's working directory.
 59→ */
 60→export interface AgentRpcContext {
 61→  /** Map of sessionId → workspace context for that session */
 62→  sessionWorkspaces: Map<
 63→    string,
 64→    {
 65→      workspacePath: string;
 66→      parentBranch: string;
 67→      defaultBranch: string;
 68→    }
 69→  >;
 70→}
 71→
 72→/**
 73→ * Hook that handles agent-initiated RPC requests from the sidecar.
 74→ *
 75→ * Returns a Map of pending requests that require user interaction.
 76→ * The rendering layer (Chat or SessionPanel) renders appropriate UI for each.
 77→ *
 78→ * @param context - Workspace info for auto-responding to data-fetch requests
 79→ * @param onPendingChange - Called whenever the pending request map changes
 80→ */
 81→export function useAgentRpcHandler(
 82→  context: AgentRpcContext,
 83→  onPendingChange?: (pending: Map<string, PendingAgentRequest>) => void
 84→) {
 85→  // Map of sessionId → pending request awaiting user interaction
 86→  const [pendingRequests, setPendingRequests] = useState<Map<string, PendingAgentRequest>>(
 87→    () => new Map()
 88→  );
 89→
 90→  // Keep refs stable across renders so handlers don't need to be recreated
 91→  const contextRef = useRef(context);
 92→  const pendingRequestsRef = useRef(pendingRequests);
 93→
 94→  // Notify parent when pending map changes
 95→  const onPendingChangeRef = useRef(onPendingChange);
 96→  const hasCommittedPendingRequestsRef = useRef(false);
 97→
 98→  useLayoutEffect(() => {
 99→    contextRef.current = context;
100→  }, [context]);
101→
102→  useLayoutEffect(() => {
103→    pendingRequestsRef.current = pendingRequests;
104→  }, [pendingRequests]);
105→
106→  useLayoutEffect(() => {
107→    onPendingChangeRef.current = onPendingChange;
108→  }, [onPendingChange]);
109→
110→  useEffect(() => {
111→    if (!hasCommittedPendingRequestsRef.current) {
112→      hasCommittedPendingRequestsRef.current = true;
113→      return;
114→    }
115→
116→    onPendingChangeRef.current?.(pendingRequests);
117→  }, [pendingRequests]);
118→
119→  const setPendingAndNotify = useCallback(
120→    (updater: (prev: Map<string, PendingAgentRequest>) => Map<string, PendingAgentRequest>) => {
121→      setPendingRequests((prev) => updater(prev));
122→    },
123→    []
124→  );
125→
126→  // ============================================================================
127→  // Shared RPC response helpers
128→  // ============================================================================
129→
130→  const sendResponse = useCallback(async (id: unknown, result: unknown) => {
131→    const message = JSON.stringify({ jsonrpc: "2.0", result, id });
132→    try {
133→      await invoke("send_sidecar_message", { message });
134→    } catch (err) {
135→      console.error("[AgentRPC] Failed to send response:", err);
136→    }
137→  }, []);
138→
139→  const sendError = useCallback(async (id: unknown, errorMessage: string) => {
140→    const message = JSON.stringify({
141→      jsonrpc: "2.0",
142→      error: { code: -32000, message: errorMessage },
143→      id,
144→    });
145→    try {
146→      await invoke("send_sidecar_message", { message });
147→    } catch (err) {
148→      console.error("[AgentRPC] Failed to send error response:", err);
149→    }
150→  }, []);
151→
152→  // ============================================================================
153→  // exitPlanMode: store pending, wait for user approve/reject
154→  // ============================================================================
155→
156→  const handleExitPlanMode = useCallback(
157→    (id: unknown, params: Record<string, unknown>) => {
158→      const sessionId = params.sessionId as string;
159→      if (!sessionId) {
160→        sendError(id, "exitPlanMode: missing sessionId");
161→        return;
162→      }
163→
164→      if (import.meta.env.DEV) {
165→        console.log("[AgentRPC] exitPlanMode pending for session:", sessionId);
166→      }
167→
168→      setPendingAndNotify((prev) => {
169→        const next = new Map(prev);
170→        next.set(sessionId, {
171→          type: "exitPlanMode",
172→          rpcId: id,
173→          sessionId,
174→          toolInput: params.toolInput,
175→        } satisfies PlanModeRequest);
176→        return next;
177→      });
178→    },
179→    [sendError, setPendingAndNotify]
180→  );
181→
182→  // ============================================================================
183→  // askUserQuestion: store pending, wait for user answers
184→  // ============================================================================
185→
186→  const handleAskUserQuestion = useCallback(
187→    (id: unknown, params: Record<string, unknown>) => {
188→      const sessionId = params.sessionId as string;
189→      const questions = params.questions as AskQuestionRequest["questions"];
190→      if (!sessionId || !Array.isArray(questions)) {
191→        sendError(id, "askUserQuestion: missing sessionId or questions");
192→        return;
193→      }
194→
195→      if (import.meta.env.DEV) {
196→        console.log(
197→          "[AgentRPC] askUserQuestion pending for session:",
198→          sessionId,
199→          questions.length,
200→          "questions"
201→        );
202→      }
203→
204→      setPendingAndNotify((prev) => {
205→        const next = new Map(prev);
206→        next.set(sessionId, {
207→          type: "askUserQuestion",
208→          rpcId: id,
209→          sessionId,
210→          questions,
211→        } satisfies AskQuestionRequest);
212→        return next;
213→      });
214→    },
215→    [sendError, setPendingAndNotify]
216→  );
217→
218→  // ============================================================================
219→  // getDiff: auto-respond using Tauri git IPC
220→  // ============================================================================
221→
222→  const handleGetDiff = useCallback(
223→    async (id: unknown, params: Record<string, unknown>) => {
224→      const sessionId = params.sessionId as string;
225→      const file = params.file as string | undefined;
226→      const stat = params.stat as boolean | undefined;
227→
228→      const ws = contextRef.current.sessionWorkspaces.get(sessionId);
229→      if (!ws) {
230→        // No workspace context for this session — respond with a descriptive error
231→        await sendResponse(id, { error: `No workspace context for session ${sessionId}` });
232→        return;
233→      }
234→
235→      try {
236→        if (file) {
237→          // Single-file diff
238→          const result = await gitDiffFile(
239→            ws.workspacePath,
240→            ws.parentBranch,
241→            ws.defaultBranch,
242→            file
243→          );
244→          await sendResponse(id, { diff: result.diff });
245→        } else if (stat) {
246→          // File list with stats
247→          const result = await gitDiffFiles(ws.workspacePath, ws.parentBranch, ws.defaultBranch);
248→          const statText = result.files
249→            .map((f) => `${f.file}: +${f.additions} -${f.deletions}`)
250→            .join("\n");
251→          await sendResponse(id, { diff: statText });
252→        } else {
253→          // All changed files list (summary, not full patch — patches can be huge)
254→          const result = await gitDiffFiles(ws.workspacePath, ws.parentBranch, ws.defaultBranch);
255→          const fileList = result.files.map((f) => f.file).join("\n");
256→          await sendResponse(id, { diff: fileList });
257→        }
258→      } catch (err: unknown) {
259→        console.error("[AgentRPC] getDiff failed:", err);
260→        await sendResponse(id, { error: getErrorMessage(err) });
261→      }
262→    },
263→    [sendResponse]
264→  );
265→
266→  // ============================================================================
267→  // diffComment: auto-respond with success (comments stored for future UI)
268→  // ============================================================================
269→
270→  const handleDiffComment = useCallback(
271→    async (id: unknown, params: Record<string, unknown>) => {
272→      // Comments from the agent are logged but not yet surfaced in the UI.
273→      // Respond with success so the agent can continue; a future PR adds the UI.
274→      if (import.meta.env.DEV) {
275→        console.log("[AgentRPC] diffComment received:", params.comments);
276→      }
277→      await sendResponse(id, { success: true });
278→    },
279→    [sendResponse]
280→  );
281→
282→  // ============================================================================
283→  // getTerminalOutput: auto-respond from Tauri PTY buffer
284→  // ============================================================================
285→
286→  const handleGetTerminalOutput = useCallback(
287→    async (id: unknown, params: Record<string, unknown>) => {
288→      // Terminal output reading via Tauri IPC.
289→      // The Rust side exposes get_terminal_output (if implemented) or we fall back
290→      // to a "no terminal output available" response so the agent can continue.
291→      try {
292→        const sessionId = params.sessionId as string;
293→        const maxLines = (params.maxLines as number | undefined) ?? 200;
294→
295→        const output = await invoke<string | null>("get_terminal_output", {
296→          sessionId,
297→          maxLines,
298→        });
299→
300→        await sendResponse(id, {
301→          output: output ?? "",
302→          source: "terminal",
303→          isRunning: false,
304→        });
305→      } catch {
306→        // Rust command not yet implemented or PTY not active — degrade gracefully
307→        await sendResponse(id, {
308→          output: "",
309→          source: "none",
310→          isRunning: false,
311→          error: "Terminal output not available",
312→        });
313→      }
314→    },
315→    [sendResponse]
316→  );
317→
318→  // ============================================================================
319→  // Public API: resolve pending requests
320→  // ============================================================================
321→
322→  /**
323→   * Called by the plan approval UI when the user clicks Approve or Reject.
324→   */
325→  const resolvePlanMode = useCallback(
326→    async (sessionId: string, approved: boolean, turnId?: string) => {
327→      const pending = pendingRequestsRef.current.get(sessionId);
328→      if (!pending || pending.type !== "exitPlanMode") return;
329→
330→      setPendingAndNotify((prev) => {
331→        const next = new Map(prev);
332→        next.delete(sessionId);
333→        return next;
334→      });
335→
336→      await sendResponse(pending.rpcId, { approved, turnId });
337→    },
338→    [sendResponse, setPendingAndNotify]
339→  );
340→
341→  /**
342→   * Called by the question UI when the user submits answers.
343→   * answers[i] is a string (single-select) or string[] (multi-select)
344→   */
345→  const resolveQuestion = useCallback(
346→    async (sessionId: string, answers: (string | string[])[]) => {
347→      const pending = pendingRequestsRef.current.get(sessionId);
348→      if (!pending || pending.type !== "askUserQuestion") return;
349→
350→      setPendingAndNotify((prev) => {
351→        const next = new Map(prev);
352→        next.delete(sessionId);
353→        return next;
354→      });
355→
356→      await sendResponse(pending.rpcId, { answers });
357→    },
358→    [sendResponse, setPendingAndNotify]
359→  );
360→
361→  // ============================================================================
362→  // Event listener
363→  // ============================================================================
364→
365→  useEffect(() => {
366→    if (!isTauriEnv) return;
367→
368→    const unlistenPromise = listen(SIDECAR_REQUEST, (event) => {
369→      const { id, method, params } = event.payload;
370→
371→      if (import.meta.env.DEV) {
372→        console.log("[AgentRPC] Received request:", method, "id:", id);
373→      }
374→
375→      match(method)
376→        .with("exitPlanMode", () => handleExitPlanMode(id, params))
377→        .with("askUserQuestion", () => handleAskUserQuestion(id, params))
378→        .with("getDiff", () => handleGetDiff(id, params))
379→        .with("diffComment", () => handleDiffComment(id, params))
380→        .with("getTerminalOutput", () => handleGetTerminalOutput(id, params))
381→        .otherwise(() => {
382→          // Not an agent-UI method — browser RPC handler or other handler will claim it
383→        });
384→    });
385→
386→    return () => {
387→      unlistenPromise.then((unlisten) => unlisten());
388→    };
389→  }, [
390→    handleExitPlanMode,
391→    handleAskUserQuestion,
392→    handleGetDiff,
393→    handleDiffComment,
394→    handleGetTerminalOutput,
395→  ]);
396→
397→  return {
398→    pendingRequests,
399→    resolvePlanMode,
400→    resolveQuestion,
401→  };
402→}
