export type RuntimeAgentType = "claude" | "codex" | "unknown";

export type ThinkingLevel = "NONE" | "LOW" | "MEDIUM" | "HIGH";

/**
 * Agent type lock constraint:
 * Once a session has messages (message_count > 0), its agent harness
 * (claude or codex) is fixed for the session's lifetime. The sidecar
 * binds to a specific SDK on first query and cannot switch mid-session.
 *
 * - Within the same harness: model switching is allowed (e.g. Sonnet → Opus)
 * - Across harnesses: requires opening a new chat tab (new session)
 *
 * The UI enforces this by disabling cross-group items in the model picker
 * when hasMessages is true. See MessageInput's model picker dropdown.
 */

// ── Agent Model Option ───────────────────────────────────────────────

interface AgentModelOption {
  /** Model identifier sent to the sidecar */
  model: string;
  /** Human-readable label */
  label: string;
  /** Show "New" badge in picker */
  isNew?: boolean;
}

// ── Agent Config ─────────────────────────────────────────────────────

/**
 * Per-agent configuration record.
 *
 * Every agent-specific behavior lives here. Adding a new agent means
 * adding one entry to AGENT_CONFIGS — no UI files need conditionals.
 *
 * - thinkingLevels: ordered cycle array, walked by cycleThinkingLevel()
 * - models: available models for the model picker dropdown
 * - groupLabel: header text in the model picker ("Claude Code", "Codex")
 */
export interface AgentConfig {
  /** DB-compatible agent_type string (matches sessions.agent_type) */
  readonly id: RuntimeAgentType;
  /** Human label for display (e.g. "Claude", "Codex") */
  readonly label: string;
  /** Group header label in model picker dropdown */
  readonly groupLabel: string;
  /** Ordered thinking levels the user cycles through on click */
  readonly thinkingLevels: readonly ThinkingLevel[];
  /** Available models, in display order */
  readonly models: readonly AgentModelOption[];
}

const AGENT_CONFIGS = {
  claude: {
    id: "claude" as const,
    label: "Claude",
    groupLabel: "Claude Code",
    thinkingLevels: ["LOW", "HIGH"] as const,
    models: [
      { model: "opus", label: "Opus 4.6" },
      { model: "sonnet", label: "Sonnet 4.6", isNew: true },
      { model: "haiku", label: "Haiku 4.5" },
    ],
  },
  codex: {
    id: "codex" as const,
    label: "Codex",
    groupLabel: "Codex",
    thinkingLevels: ["LOW", "MEDIUM", "HIGH"] as const,
    models: [
      { model: "gpt-5.3-codex", label: "GPT-5.3 Codex", isNew: true },
      { model: "gpt-5.2-codex", label: "GPT-5.2 Codex" },
      { model: "gpt-5.3-codex-spark", label: "Codex Spark" },
    ],
  },
  unknown: {
    id: "unknown" as const,
    label: "Agent",
    groupLabel: "Agent",
    thinkingLevels: ["LOW", "HIGH"] as const,
    models: [] as AgentModelOption[],
  },
} satisfies Record<RuntimeAgentType, AgentConfig>;

/** Get the config for an agent type. Falls back to "unknown" for unrecognized types. */
export function getAgentConfig(agentType: string): AgentConfig {
  const normalized = agentType.toLowerCase() as RuntimeAgentType;
  return AGENT_CONFIGS[normalized] ?? AGENT_CONFIGS.unknown;
}

/** Agent types that appear in the model picker (excludes "unknown"). */
export const MODEL_PICKER_GROUPS: readonly AgentConfig[] = [
  AGENT_CONFIGS.claude,
  AGENT_CONFIGS.codex,
];

// ── Thinking Level Cycling ───────────────────────────────────────────

/**
 * Computes the next thinking level on click.
 *
 * Walks the agent's thinkingLevels array, wrapping at the end.
 * NONE is normalized to the first entry (thinking is always "on").
 *
 * Claude: ["LOW", "HIGH"] → LOW ↔ HIGH (binary toggle)
 * Codex:  ["LOW", "MEDIUM", "HIGH"] → 3-step graduated reasoning
 */
export function cycleThinkingLevel(
  current: ThinkingLevel,
  agentType: RuntimeAgentType
): ThinkingLevel {
  const { thinkingLevels } = getAgentConfig(agentType);
  const normalized = current === "NONE" ? thinkingLevels[0] : current;
  const idx = thinkingLevels.indexOf(normalized);
  const safeIdx = idx === -1 ? 0 : idx;
  return thinkingLevels[(safeIdx + 1) % thinkingLevels.length];
}

// ── Runtime Model Options (derived from config) ──────────────────────

export interface RuntimeModelOption {
  /** Unique picker value (harness:model) */
  value: string;
  /** Actual model identifier to send to runtime/backend */
  model: string;
  label: string;
  agentType: RuntimeAgentType;
  group: "claude" | "codex";
  isNew?: boolean;
}

/** Flat model options array, derived from agent configs. */
export const RUNTIME_MODEL_OPTIONS: RuntimeModelOption[] = MODEL_PICKER_GROUPS.flatMap(
  (config) =>
    config.models.map(
      (m): RuntimeModelOption => ({
        value: `${config.id}:${m.model}`,
        model: m.model,
        label: m.label,
        agentType: config.id,
        group: config.id as "claude" | "codex",
        isNew: m.isNew,
      })
    )
);

// ── Utility functions (unchanged signatures) ─────────────────────────

export function getRuntimeAgentLabel(agentType: string): string {
  return getAgentConfig(agentType).label;
}

export function getRuntimeModelOption(model: string): RuntimeModelOption | undefined {
  const normalized = model.toLowerCase().trim();

  // New format: "harness:model" from the unified picker
  if (normalized.includes(":")) {
    return RUNTIME_MODEL_OPTIONS.find((option) => option.value === normalized);
  }

  // Backward compatibility for persisted values
  if (normalized === "codex") {
    return RUNTIME_MODEL_OPTIONS.find((option) => option.value === "codex:gpt-5.3-codex");
  }

  // Legacy plain model values default to Claude harness
  return RUNTIME_MODEL_OPTIONS.find(
    (option) => option.agentType === "claude" && option.model === normalized
  );
}

export function getRuntimeModelLabel(model: string): string {
  const option = getRuntimeModelOption(model);
  if (option) return option.label;

  const normalized = model.toLowerCase().trim();
  if (normalized.includes(":")) {
    const [, modelName] = normalized.split(":");
    return modelName || model;
  }

  return model;
}

export function getRuntimeAgentTypeForModel(model: string): RuntimeAgentType {
  const option = getRuntimeModelOption(model);
  if (option) return option.agentType;

  return model.toLowerCase().startsWith("codex:") ? "codex" : "claude";
}

export function getRuntimeModelId(model: string): string {
  const option = getRuntimeModelOption(model);
  if (option) return option.model;

  const normalized = model.toLowerCase().trim();
  if (normalized.includes(":")) {
    const [, modelName] = normalized.split(":");
    return modelName || "opus";
  }

  return normalized;
}

/**
 * Action prompt catalogue — plain-text prompts for UI-triggered agent actions.
 *
 * All prompts that originate from button clicks (not user-typed messages) live here.
 * The sidecar receives raw text via onSend(string) — no template engine, no structured format.
 *
 * Static prompts are string constants. Parameterized prompts are functions.
 * Add new exports here when adding new action buttons.
 */

// ---------------------------------------------------------------------------
// Conversation management
// ---------------------------------------------------------------------------

/** Claude Code built-in slash-command that compresses conversation context */
export const COMPACT_CONVERSATION = "/compact";

// ---------------------------------------------------------------------------
// Pull request actions
// ---------------------------------------------------------------------------

/** Instructs the agent to create a PR targeting the given branch */
export function createPRPrompt(targetBranch = "main"): string {
  return `Create a PR onto ${targetBranch}`;
}

/** Instructs the agent to resolve merge conflicts on the PR */
export const RESOLVE_CONFLICTS = "Resolve the merge conflicts on the PR and push the fix";

/** Instructs the agent to fix failing CI checks */
export const FIX_CI = "Fix the failing CI checks on the PR";

/** Instructs the agent to address review comments */
export const ADDRESS_REVIEW = "Address the review comments on the PR";

/** Instructs the agent to merge the PR */
export const MERGE_PR = "Merge the PR";

/** Code review prompt — inserted into chat input from the Code panel Review button */
export const REVIEW_CODE = `Review the current code changes in this workspace. Analyze the diff for:
- Bugs, logic errors, or edge cases
- Performance issues or unnecessary complexity
- Security concerns (hardcoded secrets, injection, unsafe patterns)
- Code style and consistency with the existing codebase
- Missing error handling or tests

Provide a concise summary of findings with specific file and line references.`;

// ---------------------------------------------------------------------------
// Workspace setup
// ---------------------------------------------------------------------------

/**
 * Instructs the agent to analyze the project and generate a opendevs.json manifest.
 * Sent when user clicks "Set up your environment" in a fresh workspace.
 * Keep in sync with .claude/skills/generate-opendevs-json/SKILL.md
 */
export const GENERATE_HIVE_JSON = `Analyze this project and generate a \`opendevs.json\` manifest file at the project root. This manifest tells the IDE how to set up workspaces, run dev servers, and execute common tasks.

**Steps:**
1. Detect the tech stack from lockfiles and project files (package.json, Cargo.toml, pyproject.toml, etc.)
2. Detect the package manager (bun, npm, yarn, pnpm, cargo, uv, pip, etc.)
3. Check for existing configs to import from: \`opendevs.json\`, \`.codex/environments/environment.toml\`
4. Extract scripts from package.json (or equivalent) and map them to tasks
5. Detect runtime requirements (.nvmrc, engines field, rust-toolchain.toml, etc.)
6. Write the \`opendevs.json\` file

**Schema:**
\`\`\`json
{
  "$schema": "https://opendevs.dev/schemas/opendevs.json",
  "version": 1,
  "name": "<project name>",
  "scripts": { "setup": "<install command>", "run": "<main dev command>" },
  "requires": { "<runtime>": ">= <version>" },
  "env": {},
  "lifecycle": { "setup": "<setup script>" },
  "tasks": {
    "<name>": "<command>",
    "<name>": { "command": "<cmd>", "icon": "<lucide-icon>", "persistent": true, "description": "..." }
  }
}
\`\`\`

**Script-to-task mapping:**
- dev/start/serve → task "dev" (icon: "play", persistent: true)
- build/compile → task "build" (icon: "hammer")
- test → task "test" (icon: "check-circle")
- lint → task "lint" (icon: "search-code")
- format/fmt → task "format" (icon: "paintbrush")
- typecheck/tsc → task "typecheck" (icon: "search-code")
- deploy/release → task "deploy" (icon: "rocket")
- storybook → task "storybook" (icon: "book-open", persistent: true)

**Rules:**
- Use string shorthand for simple tasks: \`"test": "bun run test"\`
- Use object form only when task needs icon, depends, persistent, or mode
- Always include backwards-compatible \`scripts.setup\` and \`scripts.run\` fields
- Dev tasks with long-running servers must have \`persistent: true\`
- Write the file, then show a brief summary of what was generated`;

/**
 * Instructs the agent to fix a failed setup script.
 * @param setupError - The error output from the failed setup command
 */
export function fixSetupErrorPrompt(setupError: string | null): string {
  return `The workspace setup script failed.\n\nError: ${setupError ?? "Unknown error"}\n\nPlease look at the opendevs.json manifest and the setup script, diagnose the issue, fix it, and then I'll retry the setup.`;
}

