 1→/**
 2→ * Turn Statistics Calculator
 3→ *
 4→ * Analyzes assistant turn messages to extract aggregated statistics:
 5→ * - Tool call counts (total and breakdown by tool type)
 6→ * - File changes (unique files affected)
 7→ * - Error counts
 8→ *
 9→ * Used by AssistantTurn component to display collapsed summary.
10→ */
11→
12→import type { Message, ContentBlock, ToolUseBlock, ToolResultBlock } from "@/shared/types";
13→import { isToolUseBlock } from "@shared/types/session";
14→
15→export interface TurnStats {
16→  toolCount: number;
17→  subagentCount: number;
18→  filesChanged: number;
19→  errorCount: number;
20→  toolBreakdown: Record<string, number>; // e.g., { Edit: 3, Read: 2, Bash: 3 }
21→  fileList: string[]; // List of unique file paths
22→}
23→
24→interface ParseContentFn {
25→  (content: string): (ContentBlock | string)[] | string | null;
26→}
27→
28→/**
29→ * Calculate statistics for an assistant turn
30→ *
31→ * @param messages - Array of assistant messages in this turn
32→ * @param parseContent - Function to parse message content JSON
33→ * @param toolResultMap - Map of tool_use_id to ToolResultBlock for error detection
34→ * @returns Aggregated statistics for the turn
35→ */
36→export function calculateTurnStats(
37→  messages: Message[],
38→  parseContent: ParseContentFn,
39→  toolResultMap: Map<string, ToolResultBlock>
40→): TurnStats {
41→  const stats: TurnStats = {
42→    toolCount: 0,
43→    subagentCount: 0,
44→    filesChanged: 0,
45→    errorCount: 0,
46→    toolBreakdown: {},
47→    fileList: [],
48→  };
49→
50→  const fileSet = new Set<string>();
51→
52→  messages.forEach((message) => {
53→    const contentBlocks = parseContent(message.content);
54→
55→    // Handle non-array content gracefully
56→    if (!Array.isArray(contentBlocks)) {
57→      return;
58→    }
59→
60→    contentBlocks.forEach((block) => {
61→      // Skip string blocks
62→      if (typeof block === "string") {
63→        return;
64→      }
65→
66→      // Count tool_use blocks
67→      if (isToolUseBlock(block)) {
68→        const toolUse = block;
69→        stats.toolCount++;
70→
71→        // Count subagents (Task/Agent tool_use blocks)
72→        if (toolUse.name === "Task" || toolUse.name === "Agent") {
73→          stats.subagentCount++;
74→        }
75→
76→        // Track tool breakdown
77→        stats.toolBreakdown[toolUse.name] = (stats.toolBreakdown[toolUse.name] || 0) + 1;
78→
79→        // Track file changes from tool input
80→        if (toolUse.input?.file_path) {
81→          fileSet.add(toolUse.input.file_path);
82→        }
83→
84→        // Check for errors in tool results
85→        const toolResult = toolResultMap.get(toolUse.id);
86→        if (toolResult?.is_error) {
87→          stats.errorCount++;
88→        }
89→      }
90→    });
91→  });
92→
93→  stats.filesChanged = fileSet.size;
94→  stats.fileList = Array.from(fileSet);
95→
96→  return stats;
97→}
98→

