/**
 * Turn Statistics Calculator
 *
 * Analyzes assistant turn messages to extract aggregated statistics:
 * - Tool call counts (total and breakdown by tool type)
 * - File changes (unique files affected)
 * - Error counts
 *
 * Used by AssistantTurn component to display collapsed summary.
 */

import type { Message, ContentBlock, ToolUseBlock, ToolResultBlock } from "@/shared/types";
import { isToolUseBlock } from "@shared/types/session";

export interface TurnStats {
  toolCount: number;
  subagentCount: number;
  filesChanged: number;
  errorCount: number;
  toolBreakdown: Record<string, number>; // e.g., { Edit: 3, Read: 2, Bash: 3 }
  fileList: string[]; // List of unique file paths
}

interface ParseContentFn {
  (content: string): (ContentBlock | string)[] | string | null;
}

/**
 * Calculate statistics for an assistant turn
 *
 * @param messages - Array of assistant messages in this turn
 * @param parseContent - Function to parse message content JSON
 * @param toolResultMap - Map of tool_use_id to ToolResultBlock for error detection
 * @returns Aggregated statistics for the turn
 */
export function calculateTurnStats(
  messages: Message[],
  parseContent: ParseContentFn,
  toolResultMap: Map<string, ToolResultBlock>
): TurnStats {
  const stats: TurnStats = {
    toolCount: 0,
    subagentCount: 0,
    filesChanged: 0,
    errorCount: 0,
    toolBreakdown: {},
    fileList: [],
  };

  const fileSet = new Set<string>();

  messages.forEach((message) => {
    const contentBlocks = parseContent(message.content);

    // Handle non-array content gracefully
    if (!Array.isArray(contentBlocks)) {
      return;
    }

    contentBlocks.forEach((block) => {
      // Skip string blocks
      if (typeof block === "string") {
        return;
      }

      // Count tool_use blocks
      if (isToolUseBlock(block)) {
        const toolUse = block;
        stats.toolCount++;

        // Count subagents (Task/Agent tool_use blocks)
        if (toolUse.name === "Task" || toolUse.name === "Agent") {
          stats.subagentCount++;
        }

        // Track tool breakdown
        stats.toolBreakdown[toolUse.name] = (stats.toolBreakdown[toolUse.name] || 0) + 1;

        // Track file changes from tool input
        if (toolUse.input?.file_path) {
          fileSet.add(toolUse.input.file_path);
        }

        // Check for errors in tool results
        const toolResult = toolResultMap.get(toolUse.id);
        if (toolResult?.is_error) {
          stats.errorCount++;
        }
      }
    });
  });

  stats.filesChanged = fileSet.size;
  stats.fileList = Array.from(fileSet);

  return stats;
}

/**
 * Turn Stats Header
 *
 * Displays aggregated statistics for a collapsed assistant turn.
 * Matches the exact visual alignment of BaseToolRenderer for consistency.
 *
 * Design:
 * - Perfect alignment with tool calls below (same padding, same icon size)
 * - Chevron in 14x14px container on the left (matches tool icons)
 * - Minimal, intentional - every pixel matters
 * - Visual continuity - feels part of the same system
 * - Context-aware: Shows "Collapse" when expanded, metrics when collapsed
 */

import { memo } from "react";
import { ChevronRight } from "lucide-react";
import { cn } from "@/shared/lib/utils";
import type { TurnStats } from "./utils";

interface TurnStatsHeaderProps {
  stats: TurnStats;
  isExpanded: boolean;
  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
  hiddenMessageCount: number; // Number of messages hidden when collapsed
}

/** Memoized: stats/isExpanded/hiddenMessageCount are stable for sealed turns. */
export const TurnStatsHeader = memo(function TurnStatsHeader({
  stats,
  isExpanded,
  onClick,
  hiddenMessageCount,
}: TurnStatsHeaderProps) {
  const { toolCount, subagentCount, filesChanged } = stats;

  return (
    <button
      type="button"
      onClick={onClick}
      className={cn(
        // Match BaseToolRenderer exactly: px-2 py-1.5 text-sm
        "flex items-center gap-2 px-2 py-1.5 text-sm",
        "w-full cursor-pointer text-left",
        "transition-opacity duration-150 ease-out",
        "opacity-80 hover:opacity-100",
        "focus-visible:ring-ring focus-visible:ring-2 focus-visible:outline-none"
      )}
      aria-expanded={isExpanded}
      aria-label={`${isExpanded ? "Collapse" : "Expand"} assistant turn with ${toolCount} tool calls`}
    >
      <div className="flex min-w-0 flex-1 items-center gap-2">
        {/* Chevron container - same size as tool icons (14x14px) for perfect alignment */}
        <div className="relative h-3.5 w-3.5 flex-shrink-0">
          <ChevronRight
            className={cn(
              "text-muted-foreground/50 absolute top-0 left-0 h-3.5 w-3.5 transition-[transform,opacity] duration-150 ease-out",
              isExpanded && "rotate-90"
            )}
            aria-hidden="true"
          />
        </div>

        {isExpanded ? (
          // Expanded state: Show clear action
          <span className="text-muted-foreground truncate">Collapse</span>
        ) : (
          // Collapsed state: Show metrics breakdown
          <>
            {/* Primary metric: Message count (always shown) */}
            <span className="text-muted-foreground truncate tabular-nums">
              {hiddenMessageCount} message{hiddenMessageCount !== 1 ? "s" : ""}
            </span>

            {/* Subagent count (only if > 0) */}
            {subagentCount > 0 && (
              <>
                <span className="text-muted-foreground/30" aria-hidden="true">
                  •
                </span>
                <span className="text-muted-foreground truncate tabular-nums">
                  {subagentCount} subagent{subagentCount !== 1 ? "s" : ""}
                </span>
              </>
            )}

            {/* Secondary metric: Tool calls (only if > 0) */}
            {toolCount > 0 && (
              <>
                <span className="text-muted-foreground/30" aria-hidden="true">
                  •
                </span>
                <span className="text-muted-foreground truncate tabular-nums">
                  {toolCount} tool call{toolCount !== 1 ? "s" : ""}
                </span>
              </>
            )}

            {/* Tertiary metric: Files changed (only if > 0) */}
            {filesChanged > 0 && (
              <>
                <span className="text-muted-foreground/30" aria-hidden="true">
                  •
                </span>
                <span className="text-muted-foreground truncate tabular-nums">
                  {filesChanged} file{filesChanged !== 1 ? "s" : ""} changed
                </span>
              </>
            )}
          </>
        )}
      </div>
    </button>
  );
});

